import React, { useState, useEffect } from 'react';
import api, { formatCurrency } from '../../utils/api';
import { useToast } from '../../context/ToastContext';

export default function InventoryPage() {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const { addToast } = useToast();

  useEffect(() => {
    api.get('/reports/inventory')
      .then(res => setItems(res.data.items))
      .catch(() => addToast('Không thể tải kho hàng', 'error'))
      .finally(() => setLoading(false));
  }, []);

  const filtered = filter === 'all' ? items : items.filter(i => i.stockStatus === filter);

  if (loading) return <div className="loading"><div className="spinner" /></div>;

  return (
    <div className="page">
      <div className="page-header">
        <h1>📊 Kho hàng</h1>
      </div>
      <div className="filter-bar">
        {['all','ok','low','out_of_stock'].map(f => (
          <button key={f} className={`btn btn-sm ${filter === f ? 'btn-primary' : 'btn-secondary'}`} onClick={() => setFilter(f)}>
            {f === 'all' ? 'Tất cả' : f === 'ok' ? 'Đủ hàng' : f === 'low' ? 'Sắp hết' : 'Hết hàng'}
          </button>
        ))}
      </div>
      <div className="card">
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>#</th><th>Sản phẩm</th><th>Danh mục</th><th>Tồn kho</th><th>Đơn giá</th><th>Trạng thái</th></tr>
            </thead>
            <tbody>
              {filtered.map(item => (
                <tr key={item.productID}>
                  <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{item.productID}</td>
                  <td style={{ fontWeight: 500 }}>{item.productName}</td>
                  <td style={{ color: 'var(--text-muted)' }}>{item.categoryName}</td>
                  <td style={{ fontFamily: 'Syne', fontWeight: 700 }}>{item.stockQuantity}</td>
                  <td>{formatCurrency(item.price)}</td>
                  <td><span className={`badge badge-${item.stockStatus}`}>{item.stockStatus === 'ok' ? 'Đủ hàng' : item.stockStatus === 'low' ? 'Sắp hết' : 'Hết hàng'}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
